return [{ json: {
  quarter: 'Q3 2026',
  roadmap_items: [
    { id: 'RM001', title: 'RBAC (role-based access control)', category: 'enterprise-security', eta: '2026-08-15', audience_impact: 'enterprise', confidentiality: 'internal' },
    { id: 'RM002', title: 'iOS app GA', category: 'mobile', eta: '2026-07-31', audience_impact: 'all', confidentiality: 'public' },
    { id: 'RM003', title: 'Android v1 beta', category: 'mobile', eta: '2026-09-15', audience_impact: 'all', confidentiality: 'internal' },
    { id: 'RM004', title: 'Microsoft Teams integration', category: 'integration', eta: '2026-08-30', audience_impact: 'enterprise', confidentiality: 'public' },
    { id: 'RM005', title: 'Audit log', category: 'enterprise-security', eta: '2026-08-29', audience_impact: 'enterprise', confidentiality: 'internal' },
    { id: 'RM006', title: 'Gantt chart view (deferred to Q4)', category: 'ui', eta: 'Q4 2026', audience_impact: 'all', confidentiality: 'internal' }
  ],
  stakeholders: [
    { group: 'enterprise customers', channel: 'customer success manager → email', cadence: 'monthly', sensitivity: 'medium' },
    { group: 'sales team', channel: 'Slack + weekly sync', cadence: 'weekly', sensitivity: 'high' },
    { group: 'board', channel: 'quarterly board deck', cadence: 'quarterly', sensitivity: 'high' },
    { group: 'all-hands', channel: 'company meeting', cadence: 'monthly', sensitivity: 'low' },
    { group: 'public (website/changelog)', channel: 'changelog + email newsletter', cadence: 'on release', sensitivity: 'low' }
  ],
  context: 'We have deferred Gantt chart view to Q4 and need to manage that expectation. Enterprise customers care most about RBAC and audit log. Sales needs clear ETAs for deals.'
} }];

const d = $input.first().json;
const itemsText = d.roadmap_items.map(r =>
  `  [${r.id}] ${r.title} | Category: ${r.category} | ETA: ${r.eta} | Audience: ${r.audience_impact} | Confidentiality: ${r.confidentiality}`
).join('\n');
const stakeholderText = d.stakeholders.map(s =>
  `  ${s.group} — Channel: ${s.channel} | Cadence: ${s.cadence} | Sensitivity: ${s.sensitivity}`
).join('\n');
const system = `You are a senior PM creating a stakeholder communication plan for a product roadmap. You match roadmap items to the right stakeholder groups with the right message, channel, and timing. You flag sensitive items. Return ONLY valid JSON.`;
const user = `Create a roadmap communication plan for ${d.quarter}.

Context: ${d.context}

Roadmap items:
${itemsText}

Stakeholders:
${stakeholderText}

Return JSON:
{
  "communication_plan": [
    {
      "stakeholder_group": "string",
      "channel": "string",
      "messages": [
        {
          "roadmap_item_ids": ["string"],
          "message_type": "announcement|update|expectation-setting|defer-notice",
          "suggested_timing": "string",
          "key_points": ["string"],
          "tone": "string",
          "do_not_share": ["string — items to exclude from this group"]
        }
      ]
    }
  ],
  "sensitive_items": [{ "item_id": "string", "reason": "string", "recommended_handling": "string" }],
  "deferral_notices": [{ "item": "string", "affected_groups": ["string"], "suggested_message": "string" }],
  "communication_calendar": [{ "date_or_trigger": "string", "action": "string", "groups": ["string"] }]
}`;
return [{ json: { data: d, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Communication Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.communication_plan || !Array.isArray(parsed.communication_plan)) return [{ json: { _error: true, reason: 'Missing communication_plan' } }];
return [{ json: { _error: false, plan: parsed, meta: { quarter: upstream.data.quarter, generated_at: new Date().toISOString() } } }];

const { plan: p, meta: m } = $input.first().json;
const planLines = (p.communication_plan||[]).map(sp => [
  `STAKEHOLDER GROUP: ${sp.stakeholder_group} (${sp.channel})`,
  ...(sp.messages||[]).map(msg =>
    `  Type: ${msg.message_type} | Timing: ${msg.suggested_timing}\n  Items: ${(msg.roadmap_item_ids||[]).join(', ')}\n  Key points:\n${(msg.key_points||[]).map(kp=>'    - '+kp).join('\n')}\n  Tone: ${msg.tone}${msg.do_not_share?.length ? '\n  DO NOT SHARE with this group: '+msg.do_not_share.join(', ') : ''}`
  ),
  ''
].join('\n')).join('\n');
const sensitiveLines = (p.sensitive_items||[]).map(s => `  [${s.item_id}] ${s.reason} → ${s.recommended_handling}`).join('\n');
const deferralLines = (p.deferral_notices||[]).map(d => `  ${d.item}: ${d.suggested_message} (Affected: ${d.affected_groups.join(', ')})`).join('\n');
const calendarLines = (p.communication_calendar||[]).map(c => `  ${c.date_or_trigger}: ${c.action} → ${c.groups.join(', ')}`).join('\n');
const report = [
  `ROADMAP COMMUNICATION PLAN — ${m.quarter}`,
  `Generated: ${m.generated_at}`,
  ``,
  planLines,
  `SENSITIVE ITEMS:`,
  sensitiveLines || '  (none)',
  ``,
  `DEFERRAL NOTICES:`,
  deferralLines || '  (none)',
  ``,
  `COMMUNICATION CALENDAR:`,
  calendarLines,
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
